#include <bits/stdc++.h>
using namespace std;

typedef long long ll;

vector<int> construct(int n, ll h) {
    // returns permutation of indices 1..n achieving height h
    vector<int> ans;
    int cur_n = n;
    ll cur_h = h;
    while (cur_n > 0) {
        ll min_cur = 2LL * cur_n - 1;
        ll max_cur = 1LL * cur_n * cur_n;
        if (cur_h == min_cur) {
            // decreasing order
            for (int i = cur_n; i >= 1; --i) ans.push_back(i);
            break;
        }
        if (cur_h == max_cur) {
            // increasing order
            for (int i = 1; i <= cur_n; ++i) ans.push_back(i);
            break;
        }

        // try to represent h using a set that contains cur_n
        ll rem = cur_h - min_cur;          // amount to be covered by indices < cur_n
        vector<int> subset;                // indices that will be used together with cur_n
        ll tmp = rem;
        bool success = true;
        for (int i = cur_n - 1; i >= 1; --i) {
            ll hi = 2LL * i - 1;
            if (tmp >= hi) {
                ll nxt = tmp - hi;
                ll forbid1 = 2;
                ll forbid2 = (i-1) * 1LL * (i-1) - 2;   // (i-1)^2 - 2, may be negative for small i
                if (nxt == forbid1 || nxt == forbid2) {
                    // taking i would leave an impossible remainder -> skip
                    continue;
                } else {
                    subset.push_back(i);
                    tmp = nxt;
                }
            }
        }
        if (tmp == 0) {
            // we can build the whole permutation for the current set
            vector<bool> in_set(cur_n + 1, false);
            for (int x : subset) in_set[x] = true;
            in_set[cur_n] = true;
            // first the chosen indices in increasing order
            for (int i = 1; i <= cur_n; ++i)
                if (in_set[i]) ans.push_back(i);
            // then the rest in decreasing order
            for (int i = cur_n; i >= 1; --i)
                if (!in_set[i]) ans.push_back(i);
            break;
        } else {
            // use n-first: place cur_n at the beginning and continue with n-1, h-1
            ans.push_back(cur_n);
            cur_h--;
            cur_n--;
        }
    }
    return ans;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n;
    ll h;
    cin >> n >> h;

    // feasibility check
    if (h < 2LL * n - 1 || h > 1LL * n * n || h == 1LL * n * n - 2) {
        cout << "impossible\n";
        return 0;
    }

    vector<int> perm = construct(n, h);

    // output heights
    for (size_t i = 0; i < perm.size(); ++i) {
        if (i) cout << ' ';
        cout << (2 * perm[i] - 1);
    }
    cout << '\n';

    return 0;
}
