#include <bits/stdc++.h>
using namespace std;

struct Node {
    int left, right, parent;
};

vector<int> simulate(int n, const vector<int>& left0, const vector<int>& right0, int root, bool pick_max) {
    // copy the tree
    vector<int> left = left0, right = right0, parent = vector<int>(n+1, 0);
    for (int i = 1; i <= n; ++i) {
        if (left[i]) parent[left[i]] = i;
        if (right[i]) parent[right[i]] = i;
    }
    vector<int> rev_order;
    int cur_root = root;
    while (cur_root) {
        vector<int> path;                 // nodes along the leftmost chain (until break)
        vector<pair<int,int>> candidates; // (node, depth) that are removable

        int cur = cur_root;
        int prev = 0; // previous node on the chain
        while (cur) {
            int depth = (int)path.size();
            path.push_back(cur);

            // check if cur is removable
            if (right[cur] == 0) {
                if (prev == 0) { // root
                    candidates.emplace_back(cur, depth);
                } else {
                    int p = path[depth-1]; // parent
                    if (right[p] != 0 || left[cur] == 0) {
                        candidates.emplace_back(cur, depth);
                    }
                }
            }

            // if parent has no right child and current has a left child,
            // no deeper node can be removable → stop
            if (prev != 0 && right[prev] == 0 && left[cur] != 0) {
                break;
            }

            prev = cur;
            cur = left[cur];
        }

        // There must be at least one candidate in a valid heap
        if (candidates.empty()) {
            return {}; // should not happen
        }

        // choose the candidate according to pick_max (max for minimal forward, min for maximal)
        int chosen_node, chosen_depth;
        if (pick_max) {
            int best = 0;
            for (auto& p : candidates) {
                if (p.first > best) {
                    best = p.first;
                    chosen_node = p.first;
                    chosen_depth = p.second;
                }
            }
        } else {
            int best = n+1;
            for (auto& p : candidates) {
                if (p.first < best) {
                    best = p.first;
                    chosen_node = p.first;
                    chosen_depth = p.second;
                }
            }
        }

        // ----- remove chosen_node -----
        int new_sub = left[chosen_node];   // x's left child (may be 0)
        if (chosen_depth == 0) {
            // case: remove the root
            cur_root = new_sub;
            if (cur_root) parent[cur_root] = 0;
        } else {
            // process ancestors from bottom up
            for (int i = chosen_depth-1; i >= 0; --i) {
                int a = path[i];
                int a_right = right[a];
                // swap children and attach the modified subtree
                left[a] = a_right;
                right[a] = new_sub;
                // update parent pointers of the moved subtrees
                if (a_right) parent[a_right] = a;
                if (new_sub) parent[new_sub] = a;
                new_sub = a;
            }
            cur_root = new_sub;
            if (cur_root) parent[cur_root] = 0;
        }

        rev_order.push_back(chosen_node);
    }

    // reverse to obtain the insertion order
    vector<int> forward(rev_order.rbegin(), rev_order.rend());
    return forward;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n;
    cin >> n;

    vector<int> left(n+1), right(n+1), parent(n+1, 0);
    for (int i = 1; i <= n; ++i) {
        cin >> left[i] >> right[i];
        if (left[i]) parent[left[i]] = i;
        if (right[i]) parent[right[i]] = i;
    }

    // find root
    int root = 1;
    while (root <= n && parent[root] != 0) ++root;

    // check heap property (parent <= child)
    for (int i = 1; i <= n; ++i) {
        if (left[i] && i > left[i]) {
            cout << "impossible\n";
            return 0;
        }
        if (right[i] && i > right[i]) {
            cout << "impossible\n";
            return 0;
        }
    }

    // no node may have a right child without a left child
    for (int i = 1; i <= n; ++i) {
        if (right[i] && left[i] == 0) {
            cout << "impossible\n";
            return 0;
        }
    }

    // compute minimal and maximal permutations
    vector<int> min_perm = simulate(n, left, right, root, true);
    vector<int> max_perm = simulate(n, left, right, root, false);

    // output
    for (int i = 0; i < n; ++i) {
        cout << min_perm[i] << (i+1 < n ? ' ' : '\n');
    }
    for (int i = 0; i < n; ++i) {
        cout << max_perm[i] << (i+1 < n ? ' ' : '\n');
    }

    return 0;
}
