#include <bits/stdc++.h>
using namespace std;

int main() {
    int n, k;
    cin >> n >> k;

    // helper to output a move and read new k
    auto rotate = [&](int i, int j) {
        cout << i << " " << j << endl;
        cin >> k;
    };

    // Phase 1: make sure k == n-1
    if (k == n) {
        // all symbols distinct – one move suffices
        rotate(1, 1);
        if (k == 1) return 0;
    }

    if (k < n - 1) {
        vector<bool> used(n + 1, false);
        while (k < n - 1) {
            bool increased = false;
            for (int i = 1; i <= n; ++i) {
                if (used[i]) continue;
                int start_k = k;
                int steps = 0;
                while (true) {
                    rotate(i, 1);
                    ++steps;
                    if (k == 1) return 0;
                    if (k > start_k) {
                        used[i] = true;   // now unique
                        increased = true;
                        break;
                    }
                    if (k < start_k) {
                        // revert the whole block
                        rotate(i, -steps);
                        // after revert, k should be start_k again
                        if (k == 1) return 0;
                        used[i] = true;   // it was unique
                        break;
                    }
                    // k unchanged – continue rotating
                }
                if (increased) break;
            }
        }
    }

    // now k == n-1
    vector<int> miss(n + 1, 0);

    // Phase 2: exhaustive test for every wheel
    for (int i = 1; i <= n; ++i) {
        vector<int> kvals(n);
        kvals[0] = k;
        // n-1 rotations to cover all non‑zero offsets
        for (int step = 1; step <= n - 1; ++step) {
            rotate(i, 1);
            if (k == 1) return 0;
            kvals[step] = k;
        }
        // one more rotation to return to the initial symbol
        rotate(i, 1);
        if (k == 1) return 0;

        // find the maximum k value (the "high" positions)
        int maxk = *max_element(kvals.begin(), kvals.end());
        vector<int> high;
        for (int d = 0; d < n; ++d)
            if (kvals[d] == maxk)
                high.push_back(d);

        int miss_i;
        if (high.size() == 1)
            miss_i = high[0];
        else   // size 2 – one of them is 0
            miss_i = (high[0] == 0 ? high[1] : high[0]);

        miss[i] = miss_i;
    }

    // Phase 3: compute and apply the final rotations
    int M = miss[1];
    for (int i = 1; i <= n; ++i) {
        // y_i = M - miss[i]  (mod n)
        int yi = (M - miss[i]) % n;
        if (yi < 0) yi += n;
        int rot = (-yi) % n;
        if (rot < 0) rot += n;
        if (rot != 0) {
            rotate(i, rot);
            if (k == 1) return 0;
        }
    }

    // The loop above should already have ended when k became 1.
    // If we reach here, something went wrong – but the problem guarantees a solution.
    return 0;
}
