    ios_base::sync_with_stdio(false);
    cin.tie(nullptr);

    ll n, xc, yc, xa, ya;
    cin >> n >> xc >> yc >> xa >> ya;

    // If we never need to walk south, cost is zero.
    if (yc <= ya) {
        cout << "0.0\n";
        return 0;
    }

    vector<Rect> rects(n);
    for (int i = 0; i < n; ++i) {
        ll x1, y1, x2, y2;
        cin >> x1 >> y1 >> x2 >> y2;
        // Only the y‑interval matters; horizontal movement is free.
        rects[i] = {y1, y2};
    }

    // Sort by top (y2) descending – highest rectangles first.
    sort(rects.begin(), rects.end(),
         [](const Rect& a, const Rect& b) { return a.y2 > b.y2; });

    ll cur = yc;          // current minimal y reachable without cost
    double cost = 0.0;

    for (const Rect& r : rects) {
        ll y1 = r.y1, y2 = r.y2;

        // Free use: we can ascend to the top and descend inside for free.
        if (y2 >= cur && y1 < cur) {
            cur = y1;
        }
        // Rectangle is completely below current level.
        else if (y2 < cur) {
            // Only beneficial if its top is at least the target y.
            if (y2 >= ya) {
                cost += (cur - y2);
                // If the target lies inside this rectangle, we can stop.
                if (ya >= y1) {
                    cur = ya;
                    break;
                } else {
                    cur = y1;
                }
            } else {
                // All remaining rectangles are even lower, hence useless.
                break;
            }
        }
        // Otherwise: rectangle is above current level and cannot lower cur -> ignore.
    }

    // If after processing all relevant rectangles we are still above the target,
    // we must pay for the final descent.
    if (cur > ya) {
        cost += (cur - ya);
    }

    printf("%.10f\n", cost);
    return 0;
}
