        visR[r] = true;
        X[r] = 0;
        compR[r] = compIdx;
        minA = min(minA, X[r]);
        q.push({0, r});

        while (!q.empty() && !impossible) {
            auto [typ, u] = q.front();
            q.pop();

            if (typ == 0) { // row u
                for (auto [v, d] : adjR[u]) {
                    if (!visC[v]) {
                        visC[v] = true;
                        Y[v] = X[u] - d;
                        compC[v] = compIdx;
                        ll bj = -Y[v];
                        if (bj < minB) minB = bj;
                        q.push({1, v});
                    } else {
                        if (Y[v] != X[u] - d) {
                            impossible = true;
                            break;
                        }
                    }
                }
            } else { // column u
                for (auto [rowNext, d] : adjC[u]) {
                    if (!visR[rowNext]) {
                        visR[rowNext] = true;
                        X[rowNext] = Y[u] + d;
                        compR[rowNext] = compIdx;
                        if (X[rowNext] < minA) minA = X[rowNext];
                        q.push({0, rowNext});
                    } else {
                        if (X[rowNext] != Y[u] + d) {
                            impossible = true;
                            break;
                        }
                    }
                }
            }
        }

        if (impossible) break;

        // internal non‑negativity condition: min X >= max Y  <=>  minA + minB >= 0
        if (minA + minB < 0) {
            impossible = true;
            break;
        }

        compMinA.push_back(minA);
        compMinB.push_back(minB);
        compIdx++;
    }

    if (impossible) {
        cout << "impossible\n";
        return 0;
