    ll a_tx, R_row;
    if (visR[tx]) {
        a_tx = X[tx];
        int cid = compR[tx];
        R_row = compMinA[cid];
    } else { // isolated row – we can set its value arbitrarily
        a_tx = 0;
        R_row = 0;
    }

    // information for treasure column
    ll b_ty, C_col;
    if (visC[ty]) {
        b_ty = -Y[ty];
