                for (int v : cats[idx].liked) {
                    if (cnt[v] == 0) seen.push_back(v);
                    cnt[v]++;
                }
            }
            // find a plant v with cnt[v] == numCats and L[v] == i
            int chosen = -1;
            for (int v : seen) {
                if (cnt[v] == numCats && L[v] == i) {
                    chosen = v;
                    break;
                }
            }
            // clean up
            for (int v : seen) cnt[v] = 0;

            if (chosen == -1) {
                cout << "no\n";
                return;
