#include <bits/stdc++.h>
using namespace std;
typedef long long ll;

struct Component {
    vector<int> cities;          // cities that have this component
    int deg1;                    // number of cities that have only this component
    unordered_map<int, int> sec; // other component -> count of cities with both
};

vector<int> parent;              // DSU for side nodes
vector<Component> comp;          // only valid for roots
vector<vector<int>> city_comps;  // for each city, list of components it belongs to (0‑2 elements)
ll ans = 0;

int find(int x) {
    while (parent[x] != x) {
        parent[x] = parent[parent[x]];
        x = parent[x];
    }
    return x;
}

// adds component comp_id to city (city may already have one component)
void link(int city, int comp_id) {
    auto& clist = city_comps[city];
    auto& cdata = comp[comp_id];
    if (clist.empty()) {
        clist.push_back(comp_id);
        cdata.cities.push_back(city);
        cdata.deg1++;
    } else {                        // city already has exactly one component
        int other = clist[0];
        auto& odata = comp[other];
        odata.deg1--;
        odata.sec[comp_id]++;
        cdata.cities.push_back(city);
        cdata.sec[other]++;
        clist.push_back(comp_id);
    }
}

// merges component ru (small) into rv (large)
void unionComp(int ru, int rv) {
    if (comp[ru].cities.size() > comp[rv].cities.size())
        swap(ru, rv);
    Component& small = comp[ru];
    Component& large = comp[rv];

    // ----- compute number of newly connected city pairs -----
    int overlap = 0;
    if (small.sec.count(rv)) overlap = small.sec[rv];
    int large_excl = large.cities.size() - overlap;
    ll delta = 0;

    for (int city : small.cities) {
        bool has_rv = false;
        int D = -1;
        for (int cid : city_comps[city]) {
            if (cid == rv) has_rv = true;
            else if (cid != ru) D = cid;
        }
        if (has_rv) continue;                     // overlapping city – already connected
        int already = 0;
        if (D != -1) {
            auto it = large.sec.find(D);
            if (it != large.sec.end()) already = it->second;
        }
        delta += large_excl - already;
    }

    ans += delta;

    // ----- actually merge small into large -----
    for (int city : small.cities) {
        bool has_rv = false;
        int X = -1;
        for (int cid : city_comps[city]) {
            if (cid == rv) has_rv = true;
            else if (cid != ru) X = cid;
        }

        if (has_rv) {                       // city appears in both components
            // update large: remove sec[ru], become deg1
            auto it = large.sec.find(ru);
            if (it != large.sec.end() && --it->second == 0)
                large.sec.erase(it);
            large.deg1++;
            // remove ru from city's component list
            auto& clist = city_comps[city];
            for (auto it2 = clist.begin(); it2 != clist.end(); ++it2)
                if (*it2 == ru) { clist.erase(it2); break; }
        } else if (X == -1) {               // city only in ru
            large.cities.push_back(city);
            large.deg1++;
            // replace ru by rv
            auto& clist = city_comps[city];
            for (auto it2 = clist.begin(); it2 != clist.end(); ++it2)
                if (*it2 == ru) { clist.erase(it2); break; }
            clist.push_back(rv);
        } else {                            // city has ru and another component X
            large.cities.push_back(city);
            large.sec[X]++;

            Component& compX = comp[X];
            auto it = compX.sec.find(ru);
            if (it != compX.sec.end() && --it->second == 0)
                compX.sec.erase(it);
            compX.sec[rv]++;

            // replace ru by rv in city's list
            auto& clist = city_comps[city];
            for (auto it2 = clist.begin(); it2 != clist.end(); ++it2)
                if (*it2 == ru) { *it2 = rv; break; }
        }
    }

    parent[ru] = rv;               // DSU link
    small.cities.clear();          // free memory (optional)
    small.sec.clear();
    small.deg1 = 0;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(0);

    int n, m;
    cin >> n >> m;

    vector<int> home_id(n+1, -1), dest_id(n+1, -1);
    city_comps.assign(n+1, {});

    auto createNode = [&](int city) {
        int idx = parent.size();
        parent.push_back(idx);        // becomes its own root
        comp.emplace_back();          // default constructor
        link(city, idx);
        return idx;
    };

    for (int i = 0; i < m; ++i) {
        int a, b;
        cin >> a >> b;

        if (home_id[a] == -1) home_id[a] = createNode(a);
        if (dest_id[b] == -1) dest_id[b] = createNode(b);

        int u = home_id[a], v = dest_id[b];
        int ru = find(u), rv = find(v);
        if (ru != rv) unionComp(ru, rv);
        cout << ans << "\n";
    }

    return 0;
}
