// -------------------------------------------------------------
// Digit DP for range [low, high] with condition (x % g == 0).
// Returns max count of target digit, or max count of 6+9 if combined = true.
int max_digit_count(ll low, ll high, int g, int target_digit, bool combined) {
    string hi = to_string(high);
    int len = hi.size();
    string lo = to_string(low);
    if ((int)lo.size() < len)
        lo = string(len - lo.size(), '0') + lo;

    int state_cnt = len * g * 2 * 2 * 2; // pos * rem * started * tight_low * tight_high
    vector<int> memo(state_cnt, -2);   // -2 = uncomputed, -1 = invalid, >=0 = valid max

    auto get_idx = [g](int pos, int rem, bool started, bool tl, bool th) {
        return (((pos * g + rem) * 2 + started) * 2 + tl) * 2 + th;
    };

    function<int(int,int,bool,bool,bool)> dfs = [&](int pos, int rem, bool started, bool tl, bool th) -> int {
        if (pos == len) {
            if (!started) { // number is 0
                if (rem == 0) {
                    if (!combined && target_digit == 0) return 1;
                    else return 0;
                }
                return -1;
            } else {
                return (rem == 0) ? 0 : -1;
            }
        }

        int idx = get_idx(pos, rem, started, tl, th);
        if (memo[idx] != -2) return memo[idx];

        int lo_d = lo[pos] - '0';
        int hi_d = hi[pos] - '0';
        int st = tl ? lo_d : 0;
        int en = th ? hi_d : 9;
        int best = -1;

        for (int d = st; d <= en; ++d) {
            bool nstarted = started || (d != 0);
            int nrem = (rem * 10 + d) % g;
            bool ntl = tl && (d == lo_d);
            bool nth = th && (d == hi_d);
            int inc = 0;
            if (nstarted) {
                if (combined) {
                    if (d == 6 || d == 9) inc = 1;
                } else {
                    if (d == target_digit) inc = 1;
                }
            }
            int cur = dfs(pos+1, nrem, nstarted, ntl, nth);
            if (cur >= 0) {
                if (cur + inc > best) best = cur + inc;
            }
        }
        return memo[idx] = best;
    };

    int ans = dfs(0, 0, false, true, true);
    return (ans < 0) ? 0 : ans;
}

// -------------------------------------------------------------
// Brute-force BFS for small m ( <= LIMIT )
void solve_small(ll m, const vector<int>& p) {
    int M = (int)m;
    vector<char> visited(M+1, 0);
    queue<int> q;
    visited[0] = 1;
    q.push(0);

    while (!q.empty()) {
        int s = q.front(); q.pop();
        for (int inc : p) {
            int ns = s + inc;
            if (ns > M) ns = M;
            if (!visited[ns]) {
                visited[ns] = 1;
                q.push(ns);
            }
        }
    }

    int max_digit[9] = {0}; // 0..8 individually
    int max_comb = 0;       // for 6+9

    for (int s = 0; s <= M; ++s) {
        if (visited[s]) {
            string str = to_string(s);
            int cnt[10] = {0};
            for (char c : str) cnt[c-'0']++;
            for (int d = 0; d <= 8; ++d)
                if (cnt[d] > max_digit[d]) max_digit[d] = cnt[d];
            int comb = cnt[6] + cnt[9];
            if (comb > max_comb) max_comb = comb;
        }
    }

    // output
    for (int d = 0; d <= 8; ++d) {
        int ans;
        if (d != 6) ans = max_digit[d];
        else        ans = max_comb;
        if (ans > 0)
            cout << d << " " << ans << "\n";
    }
