    cin.tie(nullptr);

    ll m;
    int n;
    cin >> m >> n;
    vector<int> p(n);
    for (int i = 0; i < n; ++i) cin >> p[i];

    // small m: brute BFS
    if (m <= LIMIT) {
        solve_small(m, p);
        return 0;
    }

    // ---------- large m ----------
    // gcd of all p
    int g = p[0];
    for (int i = 1; i < n; ++i)
        g = gcd(g, p[i]);

    // reduced generators
    vector<int> p_prime;
    for (int val : p) p_prime.push_back(val / g);
    int a0 = *min_element(p_prime.begin(), p_prime.end());

    // Dijkstra on residues mod a0
    const ll INF = 1e18;
    vector<ll> dist(a0, INF);
    dist[0] = 0;
    priority_queue<pair<ll,int>, vector<pair<ll,int>>, greater<>> pq;
    pq.push({0, 0});
    while (!pq.empty()) {
        auto [d, u] = pq.top(); pq.pop();
        if (d != dist[u]) continue;
        for (int pp : p_prime) {
            int v = (u + pp) % a0;
            ll nd = d + pp;
            if (nd < dist[v]) {
                dist[v] = nd;
                pq.push({nd, v});
            }
        }
    }
    ll Cprime = 0;   // conductor for reduced semigroup
    for (int i = 0; i < a0; ++i)
        if (dist[i] > Cprime) Cprime = dist[i];
    ll Th = g * Cprime;   // conductor for original semigroup ( ≤ 1e6 )

    // ----- low range [0, Th-1] (if Th>0) -----
    vector<int> low_max(9, 0);   // for digits 0..8 individually
    int low_comb = 0;
    if (Th > 0) {
        ll L = Th - 1;           // up to 1e6
        vector<char> reachable(L+1, 0);
        reachable[0] = 1;
        // unbounded knapsack: generate all representable numbers
        for (int coin : p) {
            if (coin > L) continue;
            for (ll v = 0; v + coin <= L; ++v)
                if (reachable[v])
                    reachable[v+coin] = 1;
