        px[i + 1] = px[i] + dr[d];
        py[i + 1] = py[i] + dc[d];
    }

    // for each step i, list of directions v (≠ dir[i]) that are valid from the cell before the move
    vector<vector<int>> other_valid(n);
    for (int i = 0; i < n; ++i) {
        int x = px[i], y = py[i];
        int d = dir[i];
