                valid[k] = true;
            }
        }
        for (int k = 0; k < 4; ++k) {
            if (k != d && valid[k]) {
                other_valid[i].push_back(k);
            }
        }
    }

    // edge counts and adjacency for the four directions
    int cnt[4][4] = {{0}};
    bool adj[4][4] = {{false}};

    // check if the current directed graph (on 4 nodes) is acyclic
    auto acyclic = [&]() -> bool {
        int indeg[4] = {0};
        for (int u = 0; u < 4; ++u)
            for (int v = 0; v < 4; ++v)
                if (adj[u][v]) ++indeg[v];
        queue<int> q;
        for (int i = 0; i < 4; ++i)
            if (indeg[i] == 0) q.push(i);
        int visited = 0;
        while (!q.empty()) {
            int u = q.front(); q.pop();
            ++visited;
            for (int v = 0; v < 4; ++v)
                if (adj[u][v]) {
                    if (--indeg[v] == 0) q.push(v);
                }
        }
        return visited == 4;
