        while (right + 1 < n) {
            int nxt = right + 1;
            int a = dir[nxt];
            // add all constraints of step nxt
            for (int b : other_valid[nxt]) {
                ++cnt[a][b];
                if (cnt[a][b] == 1) adj[a][b] = true;
            }
            if (acyclic()) {
                ++right;   // accept
