    int jumps = 0;
    int cur_end = 0;
    int farthest = 0;
    for (int i = 0; i < n; ++i) {
        farthest = max(farthest, maxR[i] + 1);
        if (i == cur_end) {
            ++jumps;
            cur_end = farthest;
            if (cur_end >= n) break;
        }
    }

    // number of cosmic ray hits = segments - 1
    cout << jumps - 1 << "\n";

    return 0;
}
